import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation } from '@angular/core';
/**
 * Bouton du design system Ori.
 *
 * - Standalone (pas de NgModule).
 * - ViewEncapsulation.None : les classes `.ori-btn*` sont définies globalement
 *   par `@govpf/ori-css` (ou `@govpf/ori-tailwind-preset` côté app).
 * - Le contenu (texte, icône, etc.) est projeté via `<ng-content>` pour
 *   permettre la composition : `<ori-button><ori-icon /> Envoyer</ori-button>`.
 */
let OriButtonComponent = class OriButtonComponent {
    constructor() {
        this.variant = 'primary';
        this.size = 'md';
        this.block = false;
        this.disabled = false;
        this.type = 'button';
    }
    get classes() {
        return [
            'ori-btn',
            `ori-btn--${this.variant}`,
            this.size !== 'md' ? `ori-btn--${this.size}` : null,
            this.block ? 'ori-btn--block' : null,
        ]
            .filter((c) => Boolean(c))
            .join(' ');
    }
    static { this.propDecorators = {
        variant: [{ type: Input }],
        size: [{ type: Input }],
        block: [{ type: Input }],
        disabled: [{ type: Input }],
        type: [{ type: Input }]
    }; }
};
OriButtonComponent = __decorate([
    Component({
        selector: 'ori-button',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `<button
    [type]="type"
    [class]="classes"
    [disabled]="disabled"
    [attr.aria-disabled]="disabled || null"
  ><ng-content></ng-content></button>`,
    })
], OriButtonComponent);
export { OriButtonComponent };
